#include <iostream>
#include <string>
#include <vector>
#include <sstream>
#include <iomanip> // For std::fixed, std::setprecision
#include <limits>  // For std::numeric_limits

// This function will contain the student's original main logic,
// with std::cin replaced by 'in' and std::cout/std::cerr replaced by 'out'.
void execute_student_main(std::istream& in, std::ostream& out) {
    float t; // Cryptic variable name
    out << "Enter temp: "; // Abbreviated prompt
    in >> t;

    // Calculation using explicit cast, slightly less common than float literals
    float f_val = t * ((float)9 / 5) + 32; // Another cryptic name, cast is correct but could be 9.0F/5.0F
                                           // No explicit F suffix for 32, which is fine but less consistent.

    out << std::fixed << std::setprecision(2) << "Result F: " << f_val << std::endl; // Abbreviated output
}

struct TestCase {
    std::string input;
    std::string expected_output;
};

int main() {
    std::vector<TestCase> test_cases = {
        {"25.0", "Result F: 77.00"},
        {"-10.0", "Result F: 14.00"},
        {"100.0", "Result F: 212.00"}
    };

    for (size_t i = 0; i < test_cases.size(); ++i) {
        std::cout << "Running Test Case " << i + 1 << "..." << std::endl;
        std::stringstream ss_in(test_cases[i].input);
        std::stringstream ss_out;

        // Call the student's logic with redirected streams
        execute_student_main(ss_in, ss_out);

        std::string actual_output = ss_out.str();

        // Remove known prompts from the actual output for comparison
        std::string cleaned_actual_output = actual_output;
        std::string prompt1 = "Enter temp: ";

        size_t p;
        p = cleaned_actual_output.find(prompt1);
        if (p != std::string::npos) cleaned_actual_output.erase(p, prompt1.length());

        // Trim leading/trailing whitespace and newlines from the cleaned output
        size_t first = cleaned_actual_output.find_first_not_of(" \t\n\r");
        size_t last = cleaned_actual_output.find_last_not_of(" \t\n\r");
        if (std::string::npos == first) {
            cleaned_actual_output = "";
        } else {
            cleaned_actual_output = cleaned_actual_output.substr(first, (last - first + 1));
        }

        std::cout << "Input: '" << test_cases[i].input << "'" << std::endl;
        std::cout << "Expected Output (substring match): '" << test_cases[i].expected_output << "'" << std::endl;
        std::cout << "Actual Output: '" << cleaned_actual_output << "'" << std::endl;

        if (cleaned_actual_output.find(test_cases[i].expected_output) != std::string::npos) {
            std::cout << "Test Result: PASSED" << std::endl;
        } else {
            std::cout << "Test Result: FAILED" << std::endl;
        }
        std::cout << "-------------------------------------" << std::endl;
    }

    return 0;
}
